import torch

def batched_cfg_step(model, x_t, t, cond_emb, uncond_emb, guidance_scale=7.5):
    """Efficient batched CFG: one model call for both branches."""
    x_double = torch.cat([x_t, x_t], dim=0)
    t_double = torch.cat([t, t], dim=0)
    emb_double = {{concat_embeddings}}

    eps_double = model(x_double, t_double, emb_double)

    eps_cond, eps_uncond = eps_double.chunk(2, dim=0)

    return eps_uncond + guidance_scale * (eps_cond - eps_uncond)

import torch

def create_tile_blend_mask(tile_h, tile_w, overlap, device='cpu'):
    """Create a blending mask for tiled inference."""
    mask_h = torch.ones(tile_h, device=device)
    if overlap > 0:
        ramp = torch.linspace(0, 1, overlap, device=device)
        mask_h[:overlap] = ramp
        mask_h[-overlap:] = {{reverse_ramp}}

    mask_w = torch.ones(tile_w, device=device)
    if overlap > 0:
        mask_w[:overlap] = ramp
        mask_w[-overlap:] = ramp.flip(0)

    mask = mask_h.unsqueeze(1) * mask_w.unsqueeze(0)
    return mask.unsqueeze(0).unsqueeze(0)

import torch

def euler_ancestral_step(denoiser, x, sigma, sigma_next):
    """One step of the ancestral Euler sampler."""
    d = (x - denoiser(x, sigma)) / sigma

    sigma_up = sigma_next * torch.sqrt(torch.tensor(
        1 - (sigma_next / sigma) ** 2
    ).clamp(min=0))
    sigma_down = {{compute_sigma_down}}

    x_next = x + (sigma_down - sigma) * d

    if sigma_next > 0:
        noise = torch.randn_like(x)
        x_next = x_next + sigma_up * noise

    return x_next

